下面的C++代码实现对list的快速排序，有关说法，错误的是（ ）。
```cpp
list<int> qSort(list<int> lst) {
    if (lst.size() <= 1) return lst;
    int pivot = lst.front();
    list<int> less, greater;
    for (auto it = ++lst.begin(); it != lst.end(); ++it) {
        if (*it < pivot) less.push_back(*it);
        else greater.push_back(*it);
    }
    less = qSort(less);
    greater = qSort(greater);
    less.push_back(pivot);
    less.insert(less.end(), greater.begin(), greater.end());
    return less;
}
```

下面C++代码中的 isPrimeA() 和 isPrimeB() 都用于判断参数N是否素数，有关其时间复杂度的正确说法是（ ）。
```cpp
bool isPrimeA(int N) {
    if (N < 2) return false;
    for (int i = 2; i * i <= N; i++) {
        if (N % i == 0) return false;
    }
    return true;
}

bool isPrimeB(int N) {
    if (N < 2) return false;
    for (int i = 2; i < N; i++) {
        if (N % i == 0) return false;
    }
    return true;
}
```

下面C++代码用于有序 list 的二分查找，有关说法错误的是（ ）。
```cpp
bool _binarySearch(list<int> lst, int key) {
    if (lst.empty()) return false;
    auto left = lst.begin();
    auto right = prev(lst.end());
    while (distance(left, right) > 0) {
        auto mid = next(left, distance(left, right) / 2);
        if (*mid == key) return true;
        else if (*mid < key) left = next(mid);
        else right = prev(mid);
    }
    return *left == key;
}
```

